import{_ as a,o as e,c as r,a2 as o}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"故宫博物院","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/forbidden-city/index.md","filePath":"landmarks/forbidden-city/index.md","lastUpdated":1784720050000}'),n={name:"landmarks/forbidden-city/index.md"};function l(i,t,d,s,g,h){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="故宫博物院" tabindex="-1">故宫博物院 <a class="header-anchor" href="#故宫博物院" aria-label="Permalink to &quot;故宫博物院&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1509265226434-5f4ddbdb2f7a?w=1200&amp;q=80" alt="故宫博物院"></p><blockquote><p>&quot;一座紫禁城，半部中国史。&quot; 六百年红墙黄瓦间，二十四位帝王的家国往事仍在回响。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>故宫，旧称紫禁城，是明清两代二十四位皇帝的皇家宫殿，也是世界上现存规模最大、保存最完整的木质结构古建筑群。它始建于明永乐四年（1406年），历时十四年建成，此后近五百年间始终是中国的权力中心。1925年，紫禁城辟为故宫博物院，昔日禁地终向世人敞开大门。</p><p>故宫占地72万平方米，建筑面积约15万平方米，传说有房屋九千九百九十九间半（实测约八千七百余间）。整座宫殿沿北京城中轴线南北展开，分为&quot;外朝&quot;与&quot;内廷&quot;两大部分：外朝以太和殿、中和殿、保和殿三大殿为中心，是举行国家大典之所；内廷以乾清宫、交泰殿、坤宁宫后三宫为中心，是帝后居住之地。左右对称、前朝后寝的布局，处处体现着&quot;天人合一&quot;与皇权至上的理念。</p><p>1987年，故宫被列入《世界文化遗产名录》。如今，它收藏文物超过186万件，是中国最大的古代文化艺术博物馆。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">8:30-17:00（16:00停止入院），周一闭馆（法定节假日除外）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">旺季（4-10月）60元；淡季（11-3月）40元；珍宝馆、钟表馆各需另购票10元</td></tr><tr><td style="text-align:left;"><strong>预约方式</strong></td><td style="text-align:left;">提前7天在&quot;故宫博物院&quot;官网或微信小程序实名预约，每日限流</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁1号线天安门东站或天安门西站下车，步行至午门检票入院</td></tr><tr><td style="text-align:left;"><strong>出入口</strong></td><td style="text-align:left;">午门（南门）为唯一入口，神武门（北门）或东华门（东门）出</td></tr><tr><td style="text-align:left;"><strong>建议游览</strong></td><td style="text-align:left;">半日（中轴线精华）或一日（含东西六宫及专馆）</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春秋两季；秋季银杏金黄、冬季雪景尤佳</td></tr></tbody></table><h2 id="子景点导览" tabindex="-1">子景点导览 <a class="header-anchor" href="#子景点导览" aria-label="Permalink to &quot;子景点导览&quot;">​</a></h2><h3 id="外朝三大殿" tabindex="-1">外朝三大殿 <a class="header-anchor" href="#外朝三大殿" aria-label="Permalink to &quot;外朝三大殿&quot;">​</a></h3><p><strong><a href="/beijing-travel-guide/landmarks/forbidden-city/wumen.html">午门</a></strong> — 故宫正门，俗称&quot;五凤楼&quot;。高37.95米的城楼翼然展开，五个门洞暗藏玄机。这里是&quot;推出午门斩首&quot;误传的源头，也是皇帝举行献俘大礼的威仪之地。</p><p><strong><a href="/beijing-travel-guide/landmarks/forbidden-city/taihe-dian.html">太和殿</a></strong> — 俗称&quot;金銮殿&quot;，中国现存最大的木结构大殿。明清两代登基、大婚、册封、命将出征等最隆重的国家大典均在此举行，殿内金漆龙椅与蟠龙藻井是皇权的终极象征。</p><p><strong><a href="/beijing-travel-guide/landmarks/forbidden-city/zhonghe-dian.html">中和殿</a></strong> — 三大殿中唯一的方形攒尖顶建筑，玲珑如亭。皇帝赴太和殿大典前在此小憩，也在此阅视祭天的祝版与亲耕的种子农具，取&quot;允执厥中&quot;之意。</p><p><strong><a href="/beijing-travel-guide/landmarks/forbidden-city/baohe-dian.html">保和殿</a></strong> — 清代殿试的固定考场，天子亲自主持的最高等级科举考试在此举行。殿后那块重达250吨的&quot;云龙阶石&quot;，是故宫最大的石雕，堪称工程奇迹。</p><h3 id="内廷后三宫" tabindex="-1">内廷后三宫 <a class="header-anchor" href="#内廷后三宫" aria-label="Permalink to &quot;内廷后三宫&quot;">​</a></h3><p><strong><a href="/beijing-travel-guide/landmarks/forbidden-city/qianqing-gong.html">乾清宫</a></strong> — 内廷之首，明代皇帝的寝宫与日常理政之所。殿内高悬的&quot;正大光明&quot;匾额背后，曾藏着决定帝国命运的秘密立储诏书。</p><p><strong><a href="/beijing-travel-guide/landmarks/forbidden-city/jiaotai-dian.html">交泰殿</a></strong> — 乾清、坤宁之间的方形小殿，皇后生辰在此受贺，清代二十五方御用宝玺珍藏于此。殿内的铜壶滴漏与大自鸣钟，是紫禁城的时间之心。</p><p><strong><a href="/beijing-travel-guide/landmarks/forbidden-city/kunning-gong.html">坤宁宫</a></strong> — 明代皇后的正宫，清代改为萨满祭祀场所，每日宰猪祭神。东暖阁则是皇帝大婚的洞房，康熙、同治、光绪三位皇帝在此度过新婚之夜。</p><h3 id="园林与专馆" tabindex="-1">园林与专馆 <a class="header-anchor" href="#园林与专馆" aria-label="Permalink to &quot;园林与专馆&quot;">​</a></h3><p><strong><a href="/beijing-travel-guide/landmarks/forbidden-city/yuhua-garden.html">御花园</a></strong> — 中轴线北端的皇家花园，堆秀山的太湖石假山、供奉玄武大帝的钦安殿、四百年古柏藤萝，在方寸之间营造出皇家园林的精致与幽深。</p><p><strong><a href="/beijing-travel-guide/landmarks/forbidden-city/zhenbao-guan.html">珍宝馆（宁寿宫区）</a></strong> — 清代宫廷珍宝的宝库，金瓯永固杯、大禹治水图玉山、皇后凤冠……每一件都是倾国之力的艺术杰作。需另购票10元。</p><p><strong><a href="/beijing-travel-guide/landmarks/forbidden-city/zhongbiao-guan.html">钟表馆（奉先殿）</a></strong> — 收藏中外钟表200余件，从英国的写字人钟到清宫造办处的花园式钟，展示18至20世纪钟表制造的巅峰水平。需另购票10元。</p><p><strong><a href="/beijing-travel-guide/landmarks/forbidden-city/jiulong-bi.html">九龙壁</a></strong> — 宁寿宫区皇极门外的琉璃照壁，九条巨龙腾跃于云海波涛之间。传说其中一块构件是楠木&quot;冒充&quot;琉璃烧制，瞒过了乾隆帝的眼睛。</p><h2 id="推荐游览路线" tabindex="-1">推荐游览路线 <a class="header-anchor" href="#推荐游览路线" aria-label="Permalink to &quot;推荐游览路线&quot;">​</a></h2><h3 id="🕐-半日精华游-约3小时" tabindex="-1">🕐 半日精华游（约3小时） <a class="header-anchor" href="#🕐-半日精华游-约3小时" aria-label="Permalink to &quot;🕐 半日精华游（约3小时）&quot;">​</a></h3><p>沿中轴线一路向北，不走回头路：</p><blockquote><p><strong>午门</strong> → 太和门广场 → <strong>太和殿</strong> → <strong>中和殿</strong> → <strong>保和殿</strong>（顺路看殿后云龙阶石）→ 乾清门 → <strong>乾清宫</strong> → <strong>交泰殿</strong> → <strong>坤宁宫</strong> → <strong>御花园</strong> → 神武门出</p></blockquote><p>这条路线串联了外朝三大殿与内廷后三宫，涵盖故宫最核心的建筑，适合时间紧凑的初访者。出神武门后可直接登上对面的景山万春亭，俯瞰紫禁城全景。</p><h3 id="🗓️-一日深度游-约6-7小时" tabindex="-1">🗓️ 一日深度游（约6-7小时） <a class="header-anchor" href="#🗓️-一日深度游-约6-7小时" aria-label="Permalink to &quot;🗓️ 一日深度游（约6-7小时）&quot;">​</a></h3><p>上午走中轴线精华（同半日游路线），下午探索两翼：</p><blockquote><p>上午：午门 → 三大殿 → 后三宫 → 御花园 下午：从御花园折返，东线游览<strong>珍宝馆</strong>（宁寿宫区，顺路看<strong>九龙壁</strong>）→ <strong>钟表馆</strong>（奉先殿）→ 东六宫 → 神武门或东华门出</p></blockquote><p>一日路线可尽览故宫精华与两大专馆。建议自带干粮，馆内餐饮选择有限且价格较高。</p><h2 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h2><ul><li><strong>务必提前预约</strong>：故宫实行实名预约制，门票提前7天开售，旺季往往开售即罄，建议定好闹钟准时抢票。</li><li><strong>带身份证</strong>：入院需刷预约时使用的身份证原件，无身份证无法入场。</li><li><strong>周一闭馆</strong>：除法定节假日外，每周一闭馆，规划行程时务必避开。</li><li><strong>轻装出行</strong>：故宫内步行距离长（中轴线全程约2公里），穿舒适的鞋；大件行李不允许带入。</li><li><strong>从南向北</strong>：午门是唯一入口，参观方向为自南向北，出北门神武门后可顺游景山公园。</li><li><strong>拍照时段</strong>：早晨开馆后和下午闭馆前光线最佳、游客最少，是拍摄空旷宫殿的黄金时间。</li></ul><h2 id="文化故事精选" tabindex="-1">文化故事精选 <a class="header-anchor" href="#文化故事精选" aria-label="Permalink to &quot;文化故事精选&quot;">​</a></h2><h3 id="为什么叫-紫禁城" tabindex="-1">为什么叫&quot;紫禁城&quot;？ <a class="header-anchor" href="#为什么叫-紫禁城" aria-label="Permalink to &quot;为什么叫&quot;紫禁城&quot;？&quot;">​</a></h3><p>&quot;紫&quot;取自天上的紫微垣——古人认为那是天帝居住的星宫；&quot;禁&quot;指皇家禁地，寻常百姓不得擅入。皇帝的居所对应天帝之宫，故名&quot;紫禁城&quot;。</p><h3 id="推出午门斩首-是真的吗" tabindex="-1">&quot;推出午门斩首&quot;是真的吗？ <a class="header-anchor" href="#推出午门斩首-是真的吗" aria-label="Permalink to &quot;&quot;推出午门斩首&quot;是真的吗？&quot;">​</a></h3><p>这是流传最广的历史误传。午门是举行献俘礼和&quot;廷杖&quot;（当众杖打大臣）的地方，并非刑场。明代确有官员在午门受廷杖而亡，但&quot;斩首&quot;一说纯属以讹传讹。详见<a href="/beijing-travel-guide/landmarks/forbidden-city/wumen.html">午门</a>。</p><h3 id="九千九百九十九间半房" tabindex="-1">九千九百九十九间半房 <a class="header-anchor" href="#九千九百九十九间半房" aria-label="Permalink to &quot;九千九百九十九间半房&quot;">​</a></h3><p>传说紫禁城有房屋9999间半，因为天庭的宫殿是一万间，人间的皇帝不敢僭越天帝的数目。实测故宫房屋约8707间，但&quot;九千九百九十九间半&quot;的说法已成为紫禁城最迷人的民间想象。</p><h3 id="龙椅背后的秘密" tabindex="-1">龙椅背后的秘密 <a class="header-anchor" href="#龙椅背后的秘密" aria-label="Permalink to &quot;龙椅背后的秘密&quot;">​</a></h3><p>太和殿的金漆龙椅是明代嘉靖年间遗物，椅背雕有蟠龙，椅座为金漆髹龙。它不只是一把椅子，而是皇权的天命象征——袁世凯称帝时曾换上一把西式高背椅，很快就被移走了。</p><h2 id="联系方式" tabindex="-1">联系方式 <a class="header-anchor" href="#联系方式" aria-label="Permalink to &quot;联系方式&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区景山前街4号</td></tr><tr><td style="text-align:left;"><strong>电话</strong></td><td style="text-align:left;">010-85007421</td></tr><tr><td style="text-align:left;"><strong>官网</strong></td><td style="text-align:left;"><a href="https://www.dpm.org.cn" target="_blank" rel="noreferrer">www.dpm.org.cn</a></td></tr></tbody></table>',46)])])}const b=a(n,[["render",l]]);export{q as __pageData,b as default};
